void example_show_addr(struct sockaddr_in *a) {
    char buf[INET_ADDRSTRLEN];
    inet_ntop(AF_INET, &a->sin_addr, buf, sizeof(buf));
    printf("Addr: %s port=%d\n", buf, ntohs(a->sin_port));
}

